from category_loader import load_category_rows
from category_paths import build_category_paths


def test_loader_preserves_parent_reference_when_parent_appears_later():
    rows = load_category_rows(
        [
            {"id": "mugs", "name": "Mugs", "parent_id": "kitchen"},
            {"id": "kitchen", "name": "Kitchen", "parent_id": None},
        ]
    )

    assert rows[0]["parent_id"] == "kitchen"


def test_path_builder_is_independent_of_row_order():
    rows = [
        {"id": "mugs", "name": "Mugs", "parent_id": "kitchen"},
        {"id": "kitchen", "name": "Kitchen", "parent_id": None},
    ]

    assert build_category_paths(rows) == {
        "mugs": "Kitchen/Mugs",
        "kitchen": "Kitchen",
    }


def test_scrambled_three_level_hierarchy_resolves_all_ancestors():
    rows = [
        {"id": "pendants", "name": "Pendants", "parent_id": "ceiling"},
        {"id": "ceiling", "name": "Ceiling", "parent_id": "lighting"},
        {"id": "lighting", "name": "Lighting", "parent_id": None},
    ]

    paths = build_category_paths(rows)

    assert paths["pendants"] == "Lighting/Ceiling/Pendants"
    assert paths["ceiling"] == "Lighting/Ceiling"
